#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N, X; scanf("%lld %lld", &N, &X);
        int64_t total = N * X;
        int64_t pizzas = (total + 3) / 4; // ceiling division
        printf("%lld\n", pizzas);
    }
    return 0;
}

